using System.Collections.Generic;
using System.Net.Http;
using System.Threading.Tasks;
using System.Web.Http;

namespace BusinessLocationAPI.Controllers
{
    public class LocationsController : ApiController
    {
        private readonly ILocationService _locationService;

        public LocationsController(ILocationService locationService)
        {
            _locationService = locationService;
        }

        [HttpGet]
        [Route("api/locations/{businessName}")]
        public async Task<IHttpActionResult> GetLocations(string businessName)
        {
            if (string.IsNullOrWhiteSpace(businessName))
            {
                return BadRequest("Business name cannot be empty.");
            }

            var locations = await _locationService.GetLocationsAsync(businessName);
            if (locations == null || locations.Count == 0)
            {
                return NotFound();
            }

            return Ok(locations);
        }
    }

    public interface ILocationService
    {
        Task<List<Location>> GetLocationsAsync(string businessName);
    }

    public class Location
    {
        public string Address { get; set; }
        public string Coordinates { get; set; }
    }

    public class LocationService : ILocationService
    {
        public async Task<List<Location>> GetLocationsAsync(string businessName)
        {
            // Simulate an asynchronous call to a data source
            await Task.Delay(100); // Simulate delay
            return new List<Location>
            {
                new Location { Address = "123 Main St", Coordinates = "40.7128,-74.0060" },
                new Location { Address = "456 Elm St", Coordinates = "34.0522,-118.2437" }
            };
        }
    }
}
